(function () {
    'use strict';

    function pluginNetflix() {
      window.plugin_netflix_ready = true;

      // --------------------------------------------------------
      // CSS inject
      // --------------------------------------------------------
      function injectStyles() {
        $('body').append("<style>@charset 'UTF-8';:root{--nf-bg:#141414;--nf-surface:#181818;--nf-red:#e50914;--nf-red-glow:rgba(229,9,20,0.35);--nf-text:#e5e5e5;--nf-text-dim:#999;--nf-radius:1em;--nf-ease:cubic-bezier(0.25,0.46,0.45,0.94);--nf-ease-out:cubic-bezier(0.16,1,0.3,1)}body{background-color:var(--nf-bg) !important}.card:not(.card--wide) .card__img{background-color:var(--nf-surface);-webkit-filter:brightness(0.85);filter:brightness(0.85);-webkit-transition:-webkit-filter .3s var(--nf-ease);transition:-webkit-filter .3s var(--nf-ease);-o-transition:filter .3s var(--nf-ease);transition:filter .3s var(--nf-ease);transition:filter .3s var(--nf-ease),-webkit-filter .3s var(--nf-ease)}.card:not(.card--wide).focus .card__img,.card:not(.card--wide).hover .card__img{-webkit-filter:brightness(1.05);filter:brightness(1.05)}.items-line .scroll--over{overflow:visible}.card:not(.card--wide) .card__view{-webkit-transition:-webkit-transform .3s var(--nf-ease),-webkit-box-shadow .3s var(--nf-ease);transition:-webkit-transform .3s var(--nf-ease),-webkit-box-shadow .3s var(--nf-ease);-o-transition:transform .3s var(--nf-ease),box-shadow .3s var(--nf-ease);transition:transform .3s var(--nf-ease),box-shadow .3s var(--nf-ease);transition:transform .3s var(--nf-ease),box-shadow .3s var(--nf-ease),-webkit-transform .3s var(--nf-ease),-webkit-box-shadow .3s var(--nf-ease);-webkit-border-radius:var(--nf-radius);border-radius:var(--nf-radius);position:relative;z-index:1}.card:not(.card--wide).focus,.card:not(.card--wide).hover{position:relative;z-index:10}.card:not(.card--wide).focus .card__view,.card:not(.card--wide).hover .card__view{-webkit-transform:scale(1.12) !important;-ms-transform:scale(1.12) !important;transform:scale(1.12) !important;-webkit-animation:none !important;animation:none !important;-webkit-box-shadow:0 0 0 2px var(--nf-red),0 8px 32px var(--nf-red-glow) !important;box-shadow:0 0 0 2px var(--nf-red),0 8px 32px var(--nf-red-glow) !important}.card:not(.card--wide).focus .card__view::after,.card:not(.card--wide).hover .card__view::after{border:none !important}.card:not(.card--wide).focus .nf-overlay,.card:not(.card--wide).hover .nf-overlay{opacity:1;-webkit-transform:translateY(0);-ms-transform:translateY(0);transform:translateY(0)}.nf-overlay{position:absolute;top:0;left:0;right:0;bottom:0;background:-webkit-gradient(linear,left bottom,left top,from(rgba(0,0,0,0.92)),color-stop(45%,rgba(0,0,0,0.55)),to(transparent));background:-webkit-linear-gradient(bottom,rgba(0,0,0,0.92) 0,rgba(0,0,0,0.55) 45%,transparent 100%);background:-o-linear-gradient(bottom,rgba(0,0,0,0.92) 0,rgba(0,0,0,0.55) 45%,transparent 100%);background:linear-gradient(to top,rgba(0,0,0,0.92) 0,rgba(0,0,0,0.55) 45%,transparent 100%);-webkit-border-radius:var(--nf-radius);border-radius:var(--nf-radius);z-index:2;display:-webkit-box;display:-webkit-flex;display:-ms-flexbox;display:flex;-webkit-box-orient:vertical;-webkit-box-direction:normal;-webkit-flex-direction:column;-ms-flex-direction:column;flex-direction:column;-webkit-box-pack:end;-webkit-justify-content:flex-end;-ms-flex-pack:end;justify-content:flex-end;padding:.9em .8em;pointer-events:none;opacity:0;-webkit-transform:translateY(0.3em);-ms-transform:translateY(0.3em);transform:translateY(0.3em);-webkit-transition:opacity .25s var(--nf-ease),-webkit-transform .25s var(--nf-ease);transition:opacity .25s var(--nf-ease),-webkit-transform .25s var(--nf-ease);-o-transition:opacity .25s var(--nf-ease),transform .25s var(--nf-ease);transition:opacity .25s var(--nf-ease),transform .25s var(--nf-ease);transition:opacity .25s var(--nf-ease),transform .25s var(--nf-ease),-webkit-transform .25s var(--nf-ease)}.nf-overlay__title{font-size:.95em;font-weight:600;color:#fff;line-height:1.3;text-shadow:0 1px 4px rgba(0,0,0,0.9);overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;line-clamp:2;-webkit-box-orient:vertical}.nf-overlay__meta{font-size:.75em;font-weight:400;color:rgba(255,255,255,0.7);margin-top:.25em;line-height:1.2;white-space:nowrap;overflow:hidden;-o-text-overflow:ellipsis;text-overflow:ellipsis}.card:not(.card--wide) .card__title,.card:not(.card--wide) .card__age{display:none}.items-line__title{font-weight:600;color:var(--nf-text);letter-spacing:.02em}.items-line__more.focus,.items-line__more.hover{background-color:var(--nf-red);border-color:var(--nf-red)}@-webkit-keyframes nf-logo-intro{0%{opacity:0;-webkit-transform:scale(3);transform:scale(3);-webkit-filter:drop-shadow(0 0 24px var(--nf-red)) brightness(2.5);filter:drop-shadow(0 0 24px var(--nf-red)) brightness(2.5)}60%{opacity:1;-webkit-filter:drop-shadow(0 0 8px var(--nf-red)) brightness(1.2);filter:drop-shadow(0 0 8px var(--nf-red)) brightness(1.2)}100%{opacity:1;-webkit-transform:scale(1);transform:scale(1);-webkit-filter:none;filter:none}}@keyframes nf-logo-intro{0%{opacity:0;-webkit-transform:scale(3);transform:scale(3);-webkit-filter:drop-shadow(0 0 24px var(--nf-red)) brightness(2.5);filter:drop-shadow(0 0 24px var(--nf-red)) brightness(2.5)}60%{opacity:1;-webkit-filter:drop-shadow(0 0 8px var(--nf-red)) brightness(1.2);filter:drop-shadow(0 0 8px var(--nf-red)) brightness(1.2)}100%{opacity:1;-webkit-transform:scale(1);transform:scale(1);-webkit-filter:none;filter:none}}.head__logo-icon{-webkit-animation:nf-logo-intro 1.2s var(--nf-ease) both;animation:nf-logo-intro 1.2s var(--nf-ease) both}@-webkit-keyframes nf-row-enter{from{opacity:0;-webkit-transform:translateY(2em);transform:translateY(2em)}to{opacity:1;-webkit-transform:translateY(0);transform:translateY(0)}}@keyframes nf-row-enter{from{opacity:0;-webkit-transform:translateY(2em);transform:translateY(2em)}to{opacity:1;-webkit-transform:translateY(0);transform:translateY(0)}}@-webkit-keyframes nf-card-enter{from{opacity:0;-webkit-transform:translateX(1.5em);transform:translateX(1.5em)}to{opacity:1;-webkit-transform:translateX(0);transform:translateX(0)}}@keyframes nf-card-enter{from{opacity:0;-webkit-transform:translateX(1.5em);transform:translateX(1.5em)}to{opacity:1;-webkit-transform:translateX(0);transform:translateX(0)}}.items-line.nf-row-animated{-webkit-animation:nf-row-enter .4s var(--nf-ease-out) both;animation:nf-row-enter .4s var(--nf-ease-out) both}.items-line.nf-row-animated .card:nth-child(1){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) 0s both;animation:nf-card-enter .35s var(--nf-ease-out) 0s both}.items-line.nf-row-animated .card:nth-child(2){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .04s both;animation:nf-card-enter .35s var(--nf-ease-out) .04s both}.items-line.nf-row-animated .card:nth-child(3){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .08s both;animation:nf-card-enter .35s var(--nf-ease-out) .08s both}.items-line.nf-row-animated .card:nth-child(4){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .12s both;animation:nf-card-enter .35s var(--nf-ease-out) .12s both}.items-line.nf-row-animated .card:nth-child(5){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .16s both;animation:nf-card-enter .35s var(--nf-ease-out) .16s both}.items-line.nf-row-animated .card:nth-child(6){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .2s both;animation:nf-card-enter .35s var(--nf-ease-out) .2s both}.items-line.nf-row-animated .card:nth-child(7){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .24s both;animation:nf-card-enter .35s var(--nf-ease-out) .24s both}.items-line.nf-row-animated .card:nth-child(8){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .28s both;animation:nf-card-enter .35s var(--nf-ease-out) .28s both}.items-line.nf-row-animated .card:nth-child(9){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .32s both;animation:nf-card-enter .35s var(--nf-ease-out) .32s both}.items-line.nf-row-animated .card:nth-child(10){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .36s both;animation:nf-card-enter .35s var(--nf-ease-out) .36s both}.items-line.nf-row-animated .card:nth-child(11){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .4s both;animation:nf-card-enter .35s var(--nf-ease-out) .4s both}.items-line.nf-row-animated .card:nth-child(12){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .44s both;animation:nf-card-enter .35s var(--nf-ease-out) .44s both}.items-line.nf-row-animated .card:nth-child(13){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .48s both;animation:nf-card-enter .35s var(--nf-ease-out) .48s both}.items-line.nf-row-animated .card:nth-child(14){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .52s both;animation:nf-card-enter .35s var(--nf-ease-out) .52s both}.items-line.nf-row-animated .card:nth-child(15){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .56s both;animation:nf-card-enter .35s var(--nf-ease-out) .56s both}.items-line.nf-row-animated .card:nth-child(16){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .6s both;animation:nf-card-enter .35s var(--nf-ease-out) .6s both}.items-line.nf-row-animated .card:nth-child(17){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .64s both;animation:nf-card-enter .35s var(--nf-ease-out) .64s both}.items-line.nf-row-animated .card:nth-child(18){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .68s both;animation:nf-card-enter .35s var(--nf-ease-out) .68s both}.items-line.nf-row-animated .card:nth-child(19){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .72s both;animation:nf-card-enter .35s var(--nf-ease-out) .72s both}.items-line.nf-row-animated .card:nth-child(20){-webkit-animation:nf-card-enter .35s var(--nf-ease-out) .76s both;animation:nf-card-enter .35s var(--nf-ease-out) .76s both}</style>");
        console.log('[netflix] styles injected');
      }

      // --------------------------------------------------------
      // Animation 1: MutationObserver — inject .nf-overlay
      // .card__title — sibling of .card__view (not child),
      // поэтому поднимаемся через closest('.card')
      // --------------------------------------------------------
      function initCardOverlays() {
        var area = document.querySelector('.activitys') || document.querySelector('.wrap__content') || document.body;
        function injectOverlays(root) {
          var views = (root || area).querySelectorAll('.card:not(.card--wide) .card__view:not([data-nf-done])');
          var count = 0;
          for (var i = 0; i < views.length; i++) {
            var view = views[i];
            var card = view.closest ? view.closest('.card') : view.parentNode && view.parentNode.parentNode;
            var title = card ? (card.querySelector('.card__title') || {}).textContent || '' : '';
            view.setAttribute('data-nf-done', '1');
            var titleEl = document.createElement('div');
            titleEl.className = 'nf-overlay__title';
            titleEl.textContent = title;
            var overlay = document.createElement('div');
            overlay.className = 'nf-overlay';
            overlay.appendChild(titleEl);

            // год + жанры
            var cardData = card ? card.card_data : null;
            var year = card ? (card.querySelector('.card__age') || {}).textContent || '' : '';
            var genreStr = '';
            if (cardData) {
              if (cardData.genres && cardData.genres.length) {
                // полные данные (страница деталей)
                genreStr = cardData.genres.slice(0, 2).map(function (g) {
                  return g.name;
                }).join(' | ');
              } else if (cardData.genre_ids && cardData.genre_ids.length) {
                // списки — маппим id→название через встроенный справочник
                try {
                  var cardType = cardData.original_name ? 'tv' : 'movie';
                  var names = Lampa.Api.sources.tmdb.getGenresNameFromIds(cardType, cardData.genre_ids);
                  genreStr = names.slice(0, 2).join(' | ');
                } catch (e) {}
              }
            }
            var metaText = [year, genreStr].filter(Boolean).join('  |  ');
            if (metaText) {
              var metaEl = document.createElement('div');
              metaEl.className = 'nf-overlay__meta';
              metaEl.textContent = metaText;
              overlay.appendChild(metaEl);
            }
            view.appendChild(overlay);
            count++;
          }
          if (count) console.log('[netflix] overlay injected:', count);
        }
        injectOverlays();
        var observer = new MutationObserver(function (mutations) {
          for (var i = 0; i < mutations.length; i++) {
            if (mutations[i].addedNodes.length) {
              injectOverlays();
              break;
            }
          }
        });
        observer.observe(area, {
          childList: true,
          subtree: true
        });
      }

      // --------------------------------------------------------
      // Animation 2: Row whoosh on activity:start
      // Сначала очищаем старые .nf-row-animated — без этого
      // анимация не реплеится при повторном переходе на экран
      // --------------------------------------------------------
      function initRowAnimations() {
        Lampa.Listener.follow('activity', function (e) {
          if (e.type !== 'start') return;
          setTimeout(function () {
            // очистка предыдущей анимации
            var old = document.querySelectorAll('.nf-row-animated');
            for (var i = 0; i < old.length; i++) {
              old[i].classList.remove('nf-row-animated');
            }
            var rows = document.querySelectorAll('.items-line');
            var count = rows.length;
            for (var j = 0; j < rows.length; j++) {
              (function (row, idx) {
                row.style.animationDelay = idx * 0.07 + 's';
                row.classList.add('nf-row-animated');
              })(rows[j], j);
            }
            console.log('[netflix] rows reset and animated:', count);
          }, 50);
        });
      }

      // --------------------------------------------------------
      // Animation 4: Netflix fixed cursor — focused card stays
      // near position 1 (one card visible to the left).
      // Monkey-patches scrollEl.Scroll.update on each row's
      // .scroll element so that when a card gains focus we
      // scroll to cardIndex-1 at the LEFT edge instead of
      // centering the focused card.
      // --------------------------------------------------------
      function initNetflixCursor() {
        function patchScroll(scrollEl) {
          if (!scrollEl || scrollEl._nfPatched) return;
          var scroll = scrollEl.Scroll;
          if (!scroll || typeof scroll.update !== 'function') return;
          var original = scroll.update.bind(scroll);
          scroll.update = function (elem, tocenter) {
            // Only intercept portrait cards in horizontal rows
            if (elem && elem.classList && elem.classList.contains('card') && !elem.classList.contains('card--wide')) {
              var row = scrollEl.closest ? scrollEl.closest('.items-line') : null;
              if (row) {
                var cards = row.querySelectorAll('.card:not(.card--wide)');
                var idx = -1;
                for (var i = 0; i < cards.length; i++) {
                  if (cards[i] === elem) {
                    idx = i;
                    break;
                  }
                }
                if (idx >= 0) {
                  var target = cards[Math.max(0, idx - 1)];
                  console.log('[netflix] cursor fix: card', idx, '→ scroll to', Math.max(0, idx - 1));
                  return original(target, false);
                }
              }
            }
            return original(elem, tocenter);
          };
          scrollEl._nfPatched = true;
          console.log('[netflix] scroll patched on', scrollEl.className || scrollEl.tagName);
        }
        function patchAllRows() {
          var rows = document.querySelectorAll('.items-line .scroll');
          for (var i = 0; i < rows.length; i++) {
            patchScroll(rows[i]);
          }
        }

        // Patch rows that exist now
        patchAllRows();

        // Patch rows added later
        var area = document.querySelector('.activitys') || document.querySelector('.wrap__content') || document.body;
        var observer = new MutationObserver(function (mutations) {
          for (var i = 0; i < mutations.length; i++) {
            if (mutations[i].addedNodes.length) {
              patchAllRows();
              break;
            }
          }
        });
        observer.observe(area, {
          childList: true,
          subtree: true
        });
      }

      // --------------------------------------------------------
      // Init
      // --------------------------------------------------------
      function init() {
        injectStyles();
        initCardOverlays();
        initRowAnimations();
        initNetflixCursor();
        console.log('[netflix] plugin ready');
      }
      if (window.appready) init();else {
        Lampa.Listener.follow('app', function (e) {
          if (e.type == 'ready') init();
        });
      }
    }
    if (!window.plugin_netflix_ready) pluginNetflix();

})();
